<?php
require_once __DIR__ . '/_bootstrap.php';
require_permission('customers.manage');
$id=(int)($_GET['id']??0); $row=db_fetch('SELECT * FROM customers WHERE tenant_id = ? AND id = ? LIMIT 1',[current_tenant_id(),$id]); if(!$row){http_response_code(404);exit('Customer not found');}
if($_SERVER['REQUEST_METHOD']==='POST'){csrf_check(); db_execute('UPDATE customers SET first_name=?, last_name=?, company=?, email=?, phone=?, address_line1=?, address_line2=?, city=?, state=?, postal_code=?, notes=?, updated_at = NOW() WHERE id = ? AND tenant_id = ?',[trim((string)$_POST['first_name']),trim((string)$_POST['last_name']),trim((string)($_POST['company']??'')),trim((string)($_POST['email']??'')),trim((string)($_POST['phone']??'')),trim((string)($_POST['address_line1']??'')),trim((string)($_POST['address_line2']??'')),trim((string)($_POST['city']??'')),trim((string)($_POST['state']??'')),trim((string)($_POST['postal_code']??'')),trim((string)($_POST['notes']??'')),$id,current_tenant_id()]); flash_success('Customer updated.'); redirect(APP_URL.'/modules/fieldora/customer_view.php?id='.$id);}
fieldora_layout_start('Edit Customer','customers'); ?>
<form method="post" class="card form-grid"><?= csrf_field() ?><input name="first_name" value="<?= e($row['first_name']) ?>" placeholder="First name"><input name="last_name" value="<?= e($row['last_name']) ?>" placeholder="Last name"><input name="company" value="<?= e($row['company']) ?>" placeholder="Company"><input name="email" value="<?= e($row['email']) ?>" placeholder="Email"><input name="phone" value="<?= e($row['phone']) ?>" placeholder="Phone"><input name="address_line1" value="<?= e($row['address_line1']) ?>" placeholder="Address 1"><input name="address_line2" value="<?= e($row['address_line2']) ?>" placeholder="Address 2"><input name="city" value="<?= e($row['city']) ?>" placeholder="City"><input name="state" value="<?= e($row['state']) ?>" placeholder="State"><input name="postal_code" value="<?= e($row['postal_code']) ?>" placeholder="Postal code"><textarea name="notes"><?= e($row['notes']) ?></textarea><button class="primary-btn" type="submit">Save customer</button></form>
<?php fieldora_layout_end();
